<template>
    <div>
        <div id="map" style="width: 100%; height: 500px;"></div>
    </div>
</template>


<script>

    import daumMap from "daum-map-wrap";

    export default {
        name: "Map",
        created() {
            this.init();
            this.markers = []; // 마커를 담을 배열
        },
        methods: {
            init() {
                daumMap(this.daumKey, "drawing", "services", "clusterer").then(maps => {
                    this.maps = maps;
                    this.geocoder = new this.maps.services.Geocoder();
                    this.places = new this.maps.services.Places();
                    // 지도를 초기화함.
                    this.initMap();
                    this.initClusterer();
                    this.eventBind();
                });
            },
            initMap() {
                let lat = 37.566826005485716;
                let lng = 126.9786567859313;
                let latLng = new this.maps.LatLng(lat, lng);
                let options = {
                    center: latLng,
                    level: 8,
                    disableDoubleClick: true,
                    draggable: true,
                    scrollwheel: true
                };
                this.map = new this.maps.Map(document.getElementById('map'), options);
            },
            eventBind() {
                this.maps.event.addListener(this.map, 'idle', this.mapIdle);
                this.maps.event.addListener(this.map, 'click', this.mapClick);
            },
            mapIdle() {
                this.setClusterer()
            },
            mapClick(e) {
                // 마커를 생성합니다
                let marker = new this.maps.Marker({
                    position: e.latLng
                });
                // 마커가 지도 위에 표시되도록 설정합니다
                marker.setMap(this.map);
                // 생성된 마커를 배열에 담음
                this.markers.push(marker);
                this.setClusterer();
            },
            initClusterer() {
                this.clusterer = new this.maps.MarkerClusterer({
                    map: this.map,
                    averageCenter: true,
                    minLevel: 7,
                    disableClickZoom: true
                });

            },
            setClusterer(){
                this.clusterer.clear();
                this.clusterer.addMarkers(this.markers);
            }

        }
    }
</script>

<style scoped>

</style>



